def euklid(a,b):
    while a != b:
        if a > b:
            a = a - b
        else:
            b = b - a
    return a

print("gcd(6,14) =", euklid(6,14))

def euklid_improved(a,b):
    while a != 0:
        if a < b:
            a, b = b, a
        a = a % b
    return b

print("gcd(6,14) =", euklid_improved(6,14))

def euklid_improved_again(a,b):
    while b != 0:
        a, b = b, a % b
    return a

print("gcd(6,14) =", euklid_improved_again(6,14))

