def bisection_recursive(f, a, b, tol):
    m = 0.5 * (a + b)
    if b-a < 2*tol:
        return m
    if f(a)*f(m) <= 0:
        return bisection_recursive(f, a, m, tol)
    else:
        return bisection_recursive(f, m, b, tol)

